1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	
14	const quoteResult = (premium: number) => ({ results: [{ premium }] });
15	
16	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
17	
18	const sum = (numbers: number[]): number =>
19	  numbers.reduce((total, n) => total + n, 0);
20	
21	const applyFirstInsuranceSurcharge = (amount: number): number =>
22	  amount + amount * FIRST_INSURANCE_SURCHARGE_RATE;
23	
24	export const runScenario = (input: any): unknown => {
25	  const items: Item[] = input.steps[0].items;
26	  const itemsBase = sum(items.map(itemBasePremium));
27	  const premium = applyFirstInsuranceSurcharge(itemsBase) + PROCESSING_FEE;
28	  return quoteResult(Math.ceil(premium));
29	};
